    else:
        print("zu hoch")
    versuch = int(input())

print("Richtig!")

class Spiel:
    def __init__(self, geheim):
        self.geheim = geheim

    def raten(self, versuch):
        if versuch == self.geheim:
            return "richtig"
        elif versuch < self.geheim:
            return "zu niedrig"
        else:
            return "zu hoch"

spiel = Spiel(42)
print(spiel.raten(30))   # zu niedrig

